import React from 'react';

export default function DrGoodesLogo({ className = '', compact = false }) {
  if (compact) {
    return (
      <div className={`inline-flex items-center ${className}`.trim()} aria-label="Dr Goodes">
        <span className="bg-brand-cream text-brand-ink px-3 py-1 text-lg leading-none font-display tracking-[0.18em] shadow-[6px_6px_0_rgba(0,0,0,0.12)] sm:text-xl">
          DR GOODES
        </span>
      </div>
    );
  }

  return (
    <div className={`inline-flex flex-col items-start gap-1 ${className}`.trim()} aria-label="Dr Goodes">
      <span className="bg-brand-cream text-brand-ink px-3 py-1 text-xl leading-none font-display tracking-[0.18em] shadow-[6px_6px_0_rgba(0,0,0,0.12)] sm:text-2xl">
        DR GOODES
      </span>
      <span className="pl-1 text-[0.6rem] font-semibold uppercase tracking-[0.45em] text-brand-ink/70 sm:text-xs">
        Brand & Signage
      </span>
    </div>
  );
}
